"QSlider {\n"
"    background: transparent;\n"
"    height: 40px;          /* 适配滑块高度 */\n"
"    border-image:  url(:/step/image/step/空步骤.png); /* 替换为你的虚线图片实际路径 */\n"
"}\n"
"\n"
"/* 1. 基础轨道：自定义虚线图片作为背景（核心修改） */\n"
"QSlider::groove:horizontal {\n"
"    height: 2px;                   /* 轨道高度（需与虚线图片高度匹配） */\n"
"    background-repeat: repeat-x;   /* 水平重复平铺图片，形成连续虚线 */\n"
"    background-position: center;   /* 图片垂直居中，避免偏移 */\n"
"    border: none;                  /* 移除原有边框虚线 */\n"
"    border-radius: 1px;\n"
"    margin: 0 12px;                /* 滑块宽度/2=24/2=12，贴合滑动范围 */\n"
"}\n"
"\n"
"/* 2. 完成部分：实线到滑块中心（消除小白点核心） */\n"
"QSlider::sub-page:horizontal {\n"
"    height: 2px;                   /* 与轨道高度一致 */\n"
"    background-color: #FFFFFF;     /* 白色实线（背景填充，无边缘断点）#FFFFFF */\n"
"    border: none;                  /* 彻底去掉所有边框 */\n"
"    border-radius: 1px;\n"
"    /* 精准限定实线范围：从轨道左边界到滑块中心 */\n"
"    margin: 0 12px;                /* 修正：补充px单位，避免样式失效 */\n"
"}\n"
"\n"
"/* 3. 滑块：PNG图标（覆盖实线终点，无白点） */\n"
"QSlider::handle:horizontal {\n"
"    image: url(:/step/image/step/smilingface.png); /* 你的PNG路径 */\n"
